CREATE TABLE IF NOT EXISTS public.ai_confirmations (
  id UUID PRIMARY KEY DEFAULT gen_random_uuid(),
  company_id UUID NOT NULL REFERENCES public.companies(id) ON DELETE CASCADE,
  decision_id UUID NOT NULL,
