  created_ids_json JSONB DEFAULT '{}',
  affected_tables_json JSONB DEFAULT '[]',
  status TEXT DEFAULT 'success' CHECK (status IN ('success', 'partial', 'failed', 'rolled_back')),
  error_json JSONB,
  can_rollback BOOLEAN DEFAULT true,
