  cliente_cpf_cnpj VARCHAR(14),
  cliente_endereco_id UUID REFERENCES public.clientes_enderecos(id),
  
  data_venda DATE NOT NULL DEFAULT CURRENT_DATE,
  data_entrega DATE,
  data_validade DATE,
