DO $$
BEGIN
  -- cost_centers
  IF NOT EXISTS (SELECT 1 FROM information_schema.columns WHERE table_name = 'cost_centers' AND column_name = 'archived_at') THEN
    ALTER TABLE public.cost_centers ADD COLUMN archived_at TIMESTAMPTZ;
  END IF;
  
