    operation_name TEXT NOT NULL,
    work_center_id UUID NOT NULL REFERENCES work_centers(id),
    planned_setup_time NUMERIC(10,2) DEFAULT 0,
    planned_run_time NUMERIC(10,2) DEFAULT 0,
